+import type { Aspect, AspectInput, AspectRecord, AspectValue } from './types';
+
+let aspectId = 0;
+
+export function createAspect<const T extends readonly [Trait, Trait, ...Trait[]]>(
+    ...inputs: T
+): Aspect<T> {
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+
+    const fields = new Set<string>();
+    const schema: Record<string, unknown> = {};
+    for (const trait of traits) {
+        if (trait[$internal].relation) {
+            throw new Error('Koota: Relations cannot be used in an aspect.');
+        }
+        for (const key of Object.keys(trait.schema)) {
+            if (fields.has(key)) {
+                throw new Error(`Koota: Aspect traits cannot share the field "${key}".`);
+            }
+            fields.add(key);
+            schema[key] = trait.schema[key as keyof typeof trait.schema];
+        }
+    }
+
+    return Object.freeze({ id: aspectId++, traits: Object.freeze(traits), schema: Object.freeze(schema), __aspect: true }) as Aspect<T>;
+}
+
+export function isAspect(value: unknown): value is Aspect {
+    return (value as Aspect | undefined)?.__aspect === true;
+}
+
+export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect<T extends Aspect>(
+    world: World,
+    entity: Entity,
+    aspect: T
+): AspectRecord<T> | undefined {
+    if (!hasAspect(world, entity, aspect)) return undefined;
+    const result: Record<string, unknown> = {};
+    for (const trait of aspect.traits) Object.assign(result, getTrait(world, entity, trait));
+    return result as AspectRecord<T>;
+}
+
+export function addAspect(world: World, entity: Entity, input: AspectInput): void {
+    const [aspect, value = {}] = Array.isArray(input) ? input : [input, {}];
+    for (const trait of aspect.traits) {
+        if (hasTrait(world, entity, trait)) continue;
+        addTrait(world, entity, [trait, pickTraitValue(trait, value)]);
+    }
+}
+
+export function removeAspect(world: World, entity: Entity, aspect: Aspect): void {
+    removeTrait(world, entity, ...aspect.traits);
+}
+
+export function setAspect<T extends Aspect>(
+    world: World,
+    entity: Entity,
+    aspect: T,
+    value: AspectValue<T> | ((previous: AspectRecord<T>) => AspectValue<T>),
+    triggerChanged = true
+): void {
+    const resolved = value instanceof Function ? value(getAspect(world, entity, aspect)!) : value;
+    for (const trait of aspect.traits) {
+        const traitValue = pickTraitValue(trait, resolved);
+        if (Object.keys(traitValue).length) setTrait(world, entity, trait, traitValue, triggerChanged);
+    }
+}
+
+function pickTraitValue(trait: Trait, value: Record<string, unknown>): Record<string, unknown> {
+    const result: Record<string, unknown> = {};
+    for (const key of Object.keys(trait.schema)) {
+        if (key in value) result[key] = value[key];
+    }
+    return result;
+}
+
+declare const $internal: unique symbol;
